const stats = $('Get Stats').all().map(i => i.json);
const pending = $('Get Pending').all().map(i => i.json);

const statusCounts = {};
stats.forEach(s => { statusCounts[s.status] = parseInt(s.count); });

const today = new Date().toLocaleDateString('vi-VN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

let message = `📊 *Daily Digest - ${today}*\n\n`;
message += `📋 *Content Status:*\n`;
message += `• Draft: ${statusCounts.draft || 0}\n`;
message += `• Generating: ${statusCounts.generating || 0}\n`;
message += `• ⏳ Pending Review: ${statusCounts.pending_review || 0}\n`;
message += `• ✅ Approved: ${statusCounts.approved || 0}\n`;
message += `• 📅 Scheduled: ${statusCounts.scheduled || 0}\n`;
message += `• 🚀 Published: ${statusCounts.published || 0}\n`;
message += `• ❌ Rejected: ${statusCounts.rejected || 0}\n`;

if (pending.length > 0) {
  message += `\n📝 *Pending Review:*\n`;
  pending.forEach((p, i) => {
    message += `${i + 1}. ${p.title} _(${p.pillar})_\n`;
  });
} else {
  message += `\n✅ No items pending review.\n`;
}

message += `\n_Review at:_ http://localhost:5678`;

return [{ json: { message } }];
